update company_config
set company_name = 'Hybrid Auto Parts',
    support_email = 'sales@hybridautoparts.local',
    phone = '818-767-5656 / 818-293-9630',
    address_line = '9787 Glenoaks Blvd',
    city = 'Sun Valley',
    state = 'CA',
    postal_code = '91352',
    hero_headline = 'OEM recycled inventory from Hybrid Auto Parts in Sun Valley',
    hero_subheadline = 'Browse locally hosted seed inventory imported from the business catalog and styled for a real customer-facing launch.',
    about_text = 'Hybrid Auto Parts is a Sun Valley, California auto recycling business focused on late-model OEM parts. This local seed set mirrors imported catalog listings and images so public browsing can be tested against realistic inventory.'
where id = 1;

delete from part_images;
delete from parts;
alter sequence parts_id_seq restart with 1;
alter sequence part_images_id_seq restart with 1;

insert into parts (
    sku,
    title,
    description,
    manufacturer,
    vehicle_make,
    vehicle_model,
    vehicle_year,
    condition,
    status,
    location_code,
    price,
    featured
) values
